var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"여전히 우리에겐 닿지도 못할 공격이군요.","JPN":"無駄な攻撃です。","ENG":"Your attacks still cannot reach us.","TWN":"你的攻擊對我們起不了作用的。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"인간이란 홀로 나약한 존재입니다.","JPN":"人間とは一人では弱い存在です。","ENG":"Humans are weak beings when they are alone.","TWN":"人類這種個體是孤獨而脆弱的存在。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"하지만 우리가 모인다면 다릅니다. 우리는 하나이자 여럿. 더 완전해질 수 있습니다.","JPN":"ですが、私たちが集まると話が違う。私たちは一人でありながら多数。さらに完全となれるのです。","ENG":"But when we gather, it becomes a different story. We are one and many. We can become more complete.","TWN":"但是如果聚在一起就另當別論了。我們既是一體，也是多個個體，我們可以變得更加完整。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신이 바라는 어둠의 정화도, 세상의 평화도 모두 가져올 수 있단 말입니다!","JPN":"あなたが望んでいる闇の浄化も、世界の平和もすべて成し遂げられるのです！","ENG":"The purification of darkness and world peace you desire... we can make them both happen!","TWN":"你所期望的淨化黑暗和世界和平都能實現！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"날 삼킨다고 해서, 달라지는 게 있을 것 같나?","JPN":"私を飲み込んで、変わるものがあると思うか？","ENG":"Do you think anything will change if you swallow me?","TWN":"你以為吞噬掉我，就能改變什麼嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식체는 절대 자신의 망집을 해소할 수 없다.","JPN":"侵食体は決して自らのの妄執を解消することができない。","ENG":"C.O.s can never resolve their obsessions.","TWN":"侵蝕體永遠被困在自己的妄念裡。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"날 삼킨 뒤엔 영원히 이루지 못할 소망을 이루기 위해 떠돌아다닐 것이 뻔하지.","JPN":"私を飲み込んだところで、叶えられない願いを叶えるために永遠を彷徨うことだろう。","ENG":"After you swallow me, you will wander about again trying to fulfill a wish that will never come true.","TWN":"吞噬我之後，你將永遠為無法實現的願望而徘徊。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그럴 리가 없지 않습니까? 당신이 바라는 것은 모두 우리에게 있습니다.","JPN":"そんなはずはありません。あなたの望むものは、すべて私たちが持っています。","ENG":"Do you really think so? We have everything you desire.","TWN":"怎麼可能？你想要的一切我們都有。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 원하는 게 너에게 있을 리가 없다. 침식체.","JPN":"私の望むものを、君は持ち合わせていない、侵食体。","ENG":"I'm certain that you cannot give me what I desire, C.O.","TWN":"我想要的東西你不可能有，侵蝕體。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 영원히 함께 싸우겠다고 맹세했습니다.","JPN":"私たちは永遠に共に戦うと誓いました。","ENG":"We vowed to fight alongside each other for an eternity.","TWN":"我們發誓要永遠並肩作戰。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 긴 세월동안, 우리는 당신을 맞이하기 위해 모든 것을 준비했어요.","JPN":"この長い間、私たちはあなたを迎え入れるためにすべてを用意してきました。","ENG":"During those long years, we have prepared everything to welcome you in.","TWN":"在那漫長的歲月裡，我們做好一切準備為要迎接你。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이제야 우리가 다시 만났는데…… 왜 이런 어리석은 선택을 하는 겁니까!","JPN":"やっと私たちが再会できたというのに……どうしてこんな愚かな選択をするのですか！","ENG":"And now, we finally meet... But why are you making such a foolish choice?!","TWN":"我們好不容易才重逢……為什麼要做出這樣愚蠢的選擇！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 기억을 갖고 있다면서 그것조차 깨닫지 못했나?","JPN":"私の記憶を持っていると言っているのに、それすらわからないのか？","ENG":"You say you have my memories, but you haven't figured out the reason?","TWN":"你說你擁有我的記憶，卻連這點都沒意識到嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그때나 지금이나 달라진 것이 없기 때문이다.","JPN":"あの時も今も、何も変わっていないからだ。","ENG":"It's because nothing has changed since then.","TWN":"那時候和現在沒有任何不同。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그때도, 지금도…… 모든 걸 잃었다는 점은 변하지 않았어.","JPN":"あの時も、今も……すべてを失ったということは変わっていない。","ENG":"The fact that I've lost everything doesn't change... Not then, not now.","TWN":"無論是那時，或是現在…我始終是失去一切的人。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"텅 비어버린 날 채우기 위해선, 침식체의 망집 따위로는 부족할 거다.","JPN":"空っぽになってしまった自分を満たすためには、侵食体の妄執などでは足りないだろう。","ENG":"And to fill this emptiness inside me, a C.O.'s obsession will not be enough.","TWN":"侵蝕體的妄念，是遠遠不夠拿來慰藉這份空虛的。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"세상의 모든 걸 삼켜 내 것으로 만들어야 할 테니까.","JPN":"世界のすべてを飲み込み、我が物にしなければいけないだろうからな。","ENG":"I will need to consume the world and make it my own to do that.","TWN":"你得吞得下整個世界才行。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"텅 비워버린 당신을 채우기 위해서라면, 우린 기꺼이 세상을 삼킬 준비가 되어 있습니다.","JPN":"空っぽになったあなたを満たすためなら、私たちは喜んで世界を飲み込む準備ができています。","ENG":"If it is to fill the emptiness inside you, we are willing to consume the entire world.","TWN":"如果是為了填補你的空虛，我們願意吞噬整個世界。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식체의 헛소리는 더 들어줄 가치도 없다.","JPN":"侵食体の戯言など、もう聞いてやる価値もない。","ENG":"Your nonsense is not worth listening to anymore, C.O.","TWN":"你的這些胡言亂語再聽下去也沒意義。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"물론, 이번에도 무언가 잃어야 될 지도 몰라.","JPN":"もちろん、今度も何かを失うことになるかもしれない。","ENG":"Of course, I might lose something this time as well.","TWN":"當然，我很清楚這次也可能會失去些什麼。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만 다행스럽게도, 나는 이제 목숨 말고는 잃을 것이 없다.","JPN":"だが幸い、私にはもう自分の命しか失うものがないのだ。","ENG":"But fortunately, I now have nothing to lose but my life.","TWN":"但幸運的是，我現在能失去的，就只有這條命。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"길동무가 되는 한이 있더라도…….","JPN":"道連れになることがあっても……","ENG":"Even if I have to take you down with me...","TWN":"就算是同歸於盡……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"반드시…… 정화해주마.","JPN":"必ず……浄化してやる。","ENG":"I will... purify you.","TWN":"也一定……要淨化你。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"거대한 침식체 치곤 굉장히 교활하군.","JPN":"巨大な侵食体の割にはかなりずる賢い。","ENG":"For a colossal C.O., it's very cunning.","TWN":"以巨型侵蝕體來說，還真是狡猾呢。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"이건 마치…… 함선이 침식체를 상대하는 방식이랑 똑같잖아.","JPN":"これはまるで……艦船が侵食体を相手にするやり方と同じだ。","ENG":"This method is... the same as when a ship is dealing with a C.O.","TWN":"這就像……艦船對抗侵蝕體的方式一模一樣。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그림자가 나타나기 시작했습니다! 저 침식체를 중심으로 전진하고 있어요!","JPN":"シャドウが出現しました！　あの侵食体を中心に前進してます！","ENG":"Shadows started to appear! They're advancing with that C.O. at the center!","TWN":"暗影出現了！正以那個侵蝕體為中心前進！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"함선을 앞세워 침식체를 압박하고 병력들을 내보내 적을 섬멸하는 방식…… 이건…….","JPN":"艦船を盾にして侵食体を圧迫し、兵力を出して敵を根絶やしにする戦術……これって……","ENG":"Deploying the ship to put pressure on C.O.s, sending troops down to annihilate the enemy... This is...","TWN":"用艦船進行壓制，再派出兵力殲滅敵人……這方式簡直就是……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"……우리가 침식체를 정화할 때 쓰던 방법이지.","JPN":"……私たちが侵食体を浄化する時に使っていたやり方だ。","ENG":"...the same method we used to purify C.O.s.","TWN":"……我們用來淨化侵蝕體的方法。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"저 침식체는 우리의 전술을 모방하고 있다.","JPN":"あの侵食体は私たちの戦術を真似している。","ENG":"That C.O. is copying our tactics.","TWN":"那些侵蝕體在模仿我們的戰術。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"함선의 기능까지 정확하게 흉내내고 있어. ","JPN":"艦船の機能まで正確にな。 ","ENG":"It is accurately mimicking the ship's functions.","TWN":"連艦船的功能都模仿得惟妙惟肖。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"저건…… ","JPN":"あれは…… ","ENG":"That’s...","TWN":"那是……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"큭……!?","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"呃……！？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"이 와중에도 나와 의식이 연결된 건가? 어찌 보면 대단한 집착이군.","JPN":"こんな状況でも私と意識が繋がっているのか？　ある意味すごい執念だ。","ENG":"Is it still connected to my consciousness? Talk about its obsession.","TWN":"在這種情況下還能與我連結意識？某種程度上來說，還真是執著。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"이번엔 뭐지? 이번엔 어떤 환각을 보여줄 셈인가?","JPN":"今度は何だ？　いったいどんな幻覚を見せるつもりだ？","ENG":"What's it this time? What kind of hallucination are you going to show me?","TWN":"這次又是什麼？這次又要讓我看到什麼幻覺？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"아디트야 님. 첫 승선 느낌은 어떠십니까?","JPN":"アーディティヤ様。初乗船はいかがですか？","ENG":"Miss Aditya, what is your first impression of being onboard?","TWN":"阿迪亞，第一次登船的感覺如何？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"괜찮으셨다니 다행입니다.","JPN":"それは何よりです。","ENG":"I'm glad you find it okay.","TWN":"滿意就好。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"앞으로 전대와 정화를 함께할 함선입니다.","JPN":"これから戦隊と共に浄化を担当することになった艦船です。","ENG":"This ship will accompany your division's purification from now on.","TWN":"今後這艘艦船將與戰鬥一起進行淨化行動。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"함선은 곧 전대의 영원한 동반자이자 집.","JPN":"艦船とは戦隊と永遠のパートナーであり、家でもあります。","ENG":"The ship will be the division's eternal companion and home.","TWN":"艦船就是戰隊永遠的夥伴和永遠的家。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"데이터 베이스로부터 아디트야 님께서 작명에 일가견이 있다는 사실을 확인했습니다.","JPN":"データベースからアーディティヤ様の命名センスが素晴らしいということを確認しました。","ENG":"We learned from the database that you are an expert in naming, Miss Aditya.","TWN":"從資料庫中確認，阿迪亞在命名方面特別擅長。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"실례가 되지 않는다면, 이 함선의 이름을 지어주시지 않겠습니까?","JPN":"よろしければ、この艦船の名前をつけてもらえませんか？","ENG":"If you don't mind, could you name the ship?","TWN":"不介意的話，能請你為這艘艦船命名嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"계속해서…… 우릴 환상으로 괴롭혔던 이유를 알겠어.","JPN":"ずっと……私たちを幻で困惑させていた理由がわかった。","ENG":"I understand why... you keep tormenting us with these hallucinations.","TWN":"我明白……你一直用幻覺折磨我們的原因了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"너의 이름을 지어주고 함께 싸워왔던 우리를 망집의 대상으로 삼았던 거였나?","JPN":"君に名前を付けて、一緒に戦ってきた私たちを妄執の対象としていたのか？","ENG":"Have you made us your obsession? The very people who named and fought with you?","TWN":"替你取名字並且一起戰鬥的我們，竟然變成你妄念的對象嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"특이 침식전 대응용 정화 함선. <color=#ffd34c>바루나스트라</color>.","JPN":"特異侵食戦対応用浄化艦船。<color=#ffd34c>ヴァルナストラ</color>。","ENG":"Special anti-Corruption Purification Ship. <color=#ffd34c>Varunastra</color>.","TWN":"特異侵蝕戰應對用淨化艦船，<color=#ffd34c>伐樓拿之艦</color>！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};